insert into public.questions (
  question,
  correct_answer,
  options,
  category,
  difficulty,
  slug,
  explanation
)
values
  ('Wie viele Spieler stehen pro Team gleichzeitig auf dem Feld?', '11', '["11","10","9","12"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-01', 'Im regulären Fußball stehen 11 Spieler pro Team inklusive Torhüter auf dem Feld. Bei Platzverweisen kann ein Team mit weniger Spielern weiterspielen.'),
  ('Wie viele Halbzeiten hat ein reguläres Fußballspiel?', '2', '["2","3","4","1"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-02', 'Ein Spiel besteht aus zwei Halbzeiten zu je 45 Minuten. Eine Verlängerung gibt es nur in Entscheidungsspielen.'),
  ('Wie lang ist die reguläre Spielzeit ohne Nachspielzeit?', '90 Minuten', '["90 Minuten","60 Minuten","80 Minuten","100 Minuten"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-03', 'Die reguläre Spielzeit beträgt 90 Minuten, aufgeteilt in zwei Halbzeiten. Dazu kommt je nach Unterbrechungen Nachspielzeit.'),
  ('Wie heißt der Neustart zu Beginn jeder Halbzeit?', 'Anstoß', '["Anstoß","Einwurf","Eckstoß","Abstoß"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-04', 'Jede Halbzeit beginnt mit dem Anstoß vom Mittelkreis. Auch nach einem Tor wird das Spiel per Anstoß fortgesetzt.'),
  ('Welche Karte bedeutet eine Verwarnung?', 'Gelbe Karte', '["Gelbe Karte","Rote Karte","Blaue Karte","Grüne Karte"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-05', 'Eine Verwarnung wird mit der gelben Karte angezeigt. Bei einer zweiten Gelben folgt die Gelb-Rote Karte und Platzverweis.'),
  ('Welche Karte bedeutet einen Platzverweis?', 'Rote Karte', '["Rote Karte","Gelbe Karte","Blaue Karte","Grüne Karte"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-06', 'Die rote Karte bedeutet Platzverweis und Unterzahl für das Team. Der Spieler darf nicht ersetzt werden.'),
  ('Wie nennt man drei Tore eines Spielers in einem Spiel?', 'Hattrick', '["Hattrick","Doppelpack","Dribbling","Abseits"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-07', 'Drei Tore eines Spielers in einem Spiel heißen Hattrick. Die Tore müssen nicht zwingend direkt hintereinander fallen.'),
  ('Was passiert, wenn der Ball die Seitenlinie vollständig überschreitet?', 'Einwurf', '["Einwurf","Eckstoß","Abstoß","Strafstoß"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-08', 'Überschreitet der Ball die Seitenlinie vollständig, gibt es Einwurf für den Gegner. Der Einwurf erfolgt an der Stelle des Ausballs.'),
  ('Was gibt es, wenn der Verteidiger den Ball zuletzt berührt und er über die Torlinie geht (kein Tor)?', 'Eckstoß', '["Eckstoß","Abstoß","Anstoß","Schiedsrichterball"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-09', 'Berührt ein Verteidiger den Ball zuletzt und er geht über die Torlinie, gibt es Eckstoß. Der Eckstoß wird von der nächstgelegenen Ecke ausgeführt.'),
  ('Was gibt es, wenn der Angreifer den Ball zuletzt berührt und er über die Torlinie geht (kein Tor)?', 'Abstoß', '["Abstoß","Eckstoß","Einwurf","Strafstoß"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-10', 'Berührt ein Angreifer den Ball zuletzt und er geht über die Torlinie, gibt es Abstoß. Der Abstoß wird vom Torraum ausgeführt.'),
  ('Wann zählt ein Tor?', 'Wenn der Ball vollständig die Torlinie überquert', '["Wenn der Ball vollständig die Torlinie überquert","Wenn der Ball die Torlinie berührt","Wenn der Ball den Pfosten trifft","Wenn der Ball den Torwart berührt"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-11', 'Ein Tor zählt nur, wenn der Ball vollständig die Torlinie zwischen den Pfosten und unter der Latte überquert. Berührung der Linie allein reicht nicht.'),
  ('Wer darf den Ball im eigenen Strafraum mit den Händen spielen?', 'Der Torhüter', '["Der Torhüter","Jeder Verteidiger","Der Kapitän","Kein Spieler"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-12', 'Nur der Torhüter darf im eigenen Strafraum den Ball mit den Händen spielen. Feldspieler begehen sonst ein Handspielvergehen.'),
  ('Welche Ausrüstung ist für Feldspieler verpflichtend?', 'Schienbeinschoner', '["Schienbeinschoner","Kopfschutz","Handschuhe","Schutzbrille"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-13', 'Schienbeinschoner sind Pflicht und müssen unter den Stutzen getragen werden. Sie dienen dem Schutz vor Verletzungen.'),
  ('Wie nennt man ein Spiel ohne Gegentor?', 'Zu Null', '["Zu Null","Doppelpack","Nachspielzeit","Abseits"]'::jsonb, 'Fußball', 'leicht', 'fussball-2026-14', 'Zu Null bedeutet, dass das Team kein Gegentor kassiert. Der Begriff wird oft bei Torhütern und Defensivleistung genutzt.'),
  ('Aus welcher Entfernung wird ein Strafstoß ausgeführt?', '11 Meter', '["11 Meter","9,15 Meter","12 Meter","16,5 Meter"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-15', 'Der Strafstoß wird vom Elfmeterpunkt aus 11 Metern Entfernung ausgeführt. Alle anderen Spieler müssen außerhalb des Strafraums bleiben.'),
  ('Wie weit müssen Gegner bei einem Freistoß mindestens entfernt sein?', '9,15 Meter', '["9,15 Meter","11 Meter","7,32 Meter","5 Meter"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-16', 'Gegner müssen beim Freistoß 9,15 m Abstand halten, was 10 Yards entspricht. Die Mauer darf sich erst bewegen, wenn der Ball im Spiel ist.'),
  ('Wie viele Spieler müssen mindestens auf dem Feld sein, damit ein Team weiterspielen darf?', '7', '["7","6","8","9"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-17', 'Ein Team benötigt mindestens 7 Spieler, sonst wird das Spiel abgebrochen. Diese Zahl ist in den Regeln festgelegt.'),
  ('Wann zählt ein Tor aus einem indirekten Freistoß?', 'Wenn der Ball zuvor von einem anderen Spieler berührt wurde', '["Wenn der Ball zuvor von einem anderen Spieler berührt wurde","Sofort nach dem Schuss","Nur bei einem Kopfball","Nie"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-18', 'Beim indirekten Freistoß muss der Ball vor einem Tor von einem anderen Spieler berührt werden. Ein direktes Tor zählt nicht.'),
  ('Welche Bedingung gilt für einen korrekten Einwurf?', 'Beide Füße am Boden und Ball über den Kopf mit beiden Händen', '["Beide Füße am Boden und Ball über den Kopf mit beiden Händen","Ein Fuß in der Luft und Ball seitlich","Ball mit einer Hand","Ball vom Boden rollen"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-19', 'Beim Einwurf müssen beide Füße auf dem Boden sein und der Ball mit beiden Händen über den Kopf geführt werden. Der Einwerfer steht an der Seitenlinie.'),
  ('Ein Spieler kann nicht im Abseits stehen, wenn er ...', 'sich in der eigenen Hälfte befindet', '["sich in der eigenen Hälfte befindet","hinter dem Torwart steht","den Ball am Fuß hat","den Ball nach hinten spielt"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-20', 'Abseits wird nur in der gegnerischen Hälfte bewertet. In der eigenen Hälfte kann man daher nicht im Abseits stehen.'),
  ('Welche Körperteile zählen für die Abseitsbewertung?', 'Alle außer Hände und Arme', '["Alle außer Hände und Arme","Nur die Füße","Nur der Kopf","Nur die Schultern"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-21', 'Für Abseits zählen alle Körperteile, mit denen ein Tor erzielt werden darf. Hände und Arme zählen nicht.'),
  ('Wie groß ist ein reguläres Fußballtor?', '7,32 m breit und 2,44 m hoch', '["7,32 m breit und 2,44 m hoch","6 m breit und 2 m hoch","8 m breit und 3 m hoch","7 m breit und 2 m hoch"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-22', 'Ein Standardtor ist 7,32 m breit und 2,44 m hoch. Diese Maße gelten im internationalen Fußball.'),
  ('Was bedeutet Nachspielzeit?', 'Zeit zum Ausgleich von Unterbrechungen wird hinzugefügt', '["Zeit zum Ausgleich von Unterbrechungen wird hinzugefügt","Ein zusätzliches Drittel","Eine Pause für Team-Meetings","Verlängerung im Pokal"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-23', 'Nachspielzeit ist zusätzliche Zeit zum Ausgleich von Unterbrechungen wie Verletzungen oder Wechseln. Sie wird vom Schiedsrichter festgelegt.'),
  ('Was ist ein direkter Freistoß?', 'Ein Freistoß, aus dem direkt ein Tor erzielt werden darf', '["Ein Freistoß, aus dem direkt ein Tor erzielt werden darf","Ein Freistoß, der nur nach Berührung zählt","Ein Freistoß aus der eigenen Hälfte","Ein Freistoß ohne Mauer"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-24', 'Bei einem direkten Freistoß darf der Ball ohne weitere Berührung direkt ins Tor gehen. Das unterscheidet ihn vom indirekten Freistoß.'),
  ('Was zeigt der Schiedsrichter bei Vorteil an?', 'Er lässt weiterspielen', '["Er lässt weiterspielen","Er pfeift sofort ab","Er zeigt Gelb","Er gibt Eckstoß"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-25', 'Bei Vorteil lässt der Schiedsrichter weiterlaufen, wenn das gefoulte Team im Vorteil bleibt. Er signalisiert dies mit beiden ausgestreckten Armen.'),
  ('Was passiert, wenn der Torhüter den Ball länger als 6 Sekunden in der Hand hält?', 'Indirekter Freistoß für den Gegner', '["Indirekter Freistoß für den Gegner","Einwurf für den Gegner","Gelbe Karte und Strafstoß","Weiterspielen ohne Konsequenz"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-26', 'Hält der Torhüter den Ball länger als sechs Sekunden, gibt es indirekten Freistoß für den Gegner. Die Regel soll Zeitspiel verhindern.'),
  ('Was bedeutet ein Doppelpass?', 'Ein Pass zum Mitspieler und sofortiger Rückpass', '["Ein Pass zum Mitspieler und sofortiger Rückpass","Zwei Tore in einem Spiel","Ein langer Diagonalpass","Ein Pass zum Torwart"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-27', 'Der Doppelpass ist ein kurzes Passspiel mit sofortigem Rückpass. Er dient dazu, Gegenspieler auszuspielen.'),
  ('Was ist eine Grätsche?', 'Ein Rutschen in den Ball zum Tackling', '["Ein Rutschen in den Ball zum Tackling","Ein Schuss aus der Drehung","Ein hoher Pass","Ein Spielzug bei Eckstoß"]'::jsonb, 'Fußball', 'mittel', 'fussball-2026-28', 'Eine Grätsche ist ein Tackling im Rutschen. Sie ist nur fair, wenn zuerst der Ball gespielt wird.'),
  ('Wann steht ein Spieler im Abseits?', 'Wenn er sich in der gegnerischen Hälfte befindet und näher zur Torlinie ist als Ball und vorletzter Gegner', '["Wenn er sich in der gegnerischen Hälfte befindet und näher zur Torlinie ist als Ball und vorletzter Gegner","Wenn er den Ball nach hinten spielt","Wenn er in der eigenen Hälfte steht","Wenn er beim Einwurf den Ball erhält"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-29', 'Abseits liegt vor, wenn ein Spieler in der gegnerischen Hälfte näher zur Torlinie steht als Ball und vorletzter Gegner. Strafbar ist es erst bei aktivem Eingreifen ins Spiel.'),
  ('Ein Spieler steht auf gleicher Höhe mit dem vorletzten Gegner. Abseits?', 'Nein, gleiche Höhe ist nicht abseits', '["Nein, gleiche Höhe ist nicht abseits","Ja, immer abseits","Nur bei Eckstoß","Nur bei Abstoß"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-30', 'Gleiche Höhe mit dem vorletzten Gegner oder dem Ball gilt nicht als Abseits. In solchen Fällen ist das Spiel weiterlaufen zu lassen.'),
  ('Beim Strafstoß darf der Schütze den Ball erneut spielen ...', 'erst nachdem ein anderer Spieler den Ball berührt hat', '["erst nachdem ein anderer Spieler den Ball berührt hat","sofort nach dem Schuss","nur wenn der Torwart abwehrt","niemals"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-31', 'Der Schütze darf den Ball erst erneut spielen, nachdem ein anderer Spieler ihn berührt hat. Das verhindert einen doppelten Kontakt.'),
  ('Wo müssen die Gegenspieler beim Anstoß stehen?', 'Außerhalb des Mittelkreises und mindestens 9,15 m vom Ball entfernt', '["Außerhalb des Mittelkreises und mindestens 9,15 m vom Ball entfernt","Im Mittelkreis","Auf der Mittellinie direkt am Ball","Im Strafraum"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-32', 'Gegenspieler müssen außerhalb des Mittelkreises stehen und mindestens 9,15 m Abstand halten. Erst mit der Ballbewegung ist der Ball im Spiel.'),
  ('Was passiert, wenn der Schiedsrichter den Ball berührt und dadurch ein aussichtsreicher Angriff entsteht?', 'Schiedsrichterball', '["Schiedsrichterball","Freistoß für die angreifende Mannschaft","Einwurf","Strafstoß"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-33', 'Wenn der Schiedsrichter den Ball berührt und dadurch eine Angriffschance entsteht, wird mit Schiedsrichterball fortgesetzt. Das stellt Neutralität wieder her.'),
  ('Welche Vorgabe gilt für den Torwart beim Strafstoß vor dem Schuss?', 'Mindestens ein Fuß auf oder über der Torlinie', '["Mindestens ein Fuß auf oder über der Torlinie","Beide Füße hinter der Linie","Beide Füße vor der Linie","Er darf sich frei bewegen"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-34', 'Der Torwart muss mindestens einen Fuß auf oder über der Torlinie haben. Er darf sich seitlich bewegen, aber nicht nach vorne.'),
  ('Wie signalisiert der Schiedsrichter einen indirekten Freistoß?', 'Er hebt den Arm nach oben', '["Er hebt den Arm nach oben","Er zeigt Gelb","Er pfeift ohne Handzeichen","Er zeigt auf den Mittelpunkt"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-35', 'Der Schiedsrichter hebt den Arm, um indirekten Freistoß anzuzeigen. Der Arm bleibt oben, bis der Ball von einem zweiten Spieler berührt wird.'),
  ('Was gilt für den Torhüter beim absichtlichen Rückpass mit dem Fuß eines Mitspielers?', 'Er darf den Ball nicht mit den Händen aufnehmen', '["Er darf den Ball nicht mit den Händen aufnehmen","Er darf den Ball fangen","Es gibt Einwurf","Es gibt Eckstoß"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-36', 'Ein absichtlicher Rückpass mit dem Fuß darf vom Torhüter nicht mit der Hand aufgenommen werden. Gleiches gilt nach einem Einwurf eines Mitspielers.'),
  ('Welches Vergehen führt zu einem indirekten Freistoß?', 'Gefährliches Spiel ohne Kontakt', '["Gefährliches Spiel ohne Kontakt","Treten des Gegners","Stoßen des Gegners","Handspiel im Strafraum"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-37', 'Gefährliches Spiel ohne Kontakt führt zu einem indirekten Freistoß. Beispiel ist ein hoher Fuß in Kopfhöhe.'),
  ('Der Ball platzt während des Spiels. Wie wird fortgesetzt?', 'Schiedsrichterball', '["Schiedsrichterball","Einwurf","Abstoß","Eckstoß"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-38', 'Platzt der Ball oder wird unspielbar, unterbricht der Schiedsrichter und setzt mit Schiedsrichterball fort. Der Ball wird ersetzt.'),
  ('Was passiert, wenn ein Spieler einen Freistoß ausführt und den Ball ohne weiteren Kontakt erneut spielt?', 'Indirekter Freistoß für den Gegner', '["Indirekter Freistoß für den Gegner","Weiterspielen","Gelbe Karte und Strafstoß","Wiederholung des Freistoßes"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-39', 'Spielt der ausführende Spieler den Ball erneut, bevor ein anderer ihn berührt, gibt es indirekten Freistoß für den Gegner. Das gilt für viele Spielfortsetzungen.'),
  ('Kann direkt aus dem Anstoß ein Tor erzielt werden?', 'Ja, direkt ins gegnerische Tor', '["Ja, direkt ins gegnerische Tor","Nein, erst nach einer Berührung","Nur nach Abseits","Nur nach einem Pass"]'::jsonb, 'Fußball', 'schwer', 'fussball-2026-40', 'Ein Tor kann direkt aus dem Anstoß erzielt werden, wenn der Ball ins gegnerische Tor geht. Der Ball muss dabei klar in Bewegung sein.');

with translations as (
  select * from (values
  ('fussball-2026-01', 'How many players are on the field per team at the same time?', '["11","10","9","12"]'::jsonb, '11', 'In standard football, each team fields 11 players including a goalkeeper. After red cards a team may continue with fewer players.'),
  ('fussball-2026-02', 'How many halves does a standard football match have?', '["2","3","4","1"]'::jsonb, '2', 'A match consists of two halves of 45 minutes. Extra time is only used in knockout games.'),
  ('fussball-2026-03', 'How long is the regular playing time without added time?', '["90 minutes","60 minutes","80 minutes","100 minutes"]'::jsonb, '90 minutes', 'Regular time is 90 minutes split into two halves. Added time is played to compensate for stoppages.'),
  ('fussball-2026-04', 'What is the restart at the beginning of each half?', '["Kick-off","Throw-in","Corner kick","Goal kick"]'::jsonb, 'Kick-off', 'Each half starts with a kick-off from the center spot. After a goal, play also restarts with a kick-off.'),
  ('fussball-2026-05', 'Which card means a caution?', '["Yellow card","Red card","Blue card","Green card"]'::jsonb, 'Yellow card', 'A caution is shown with the yellow card. A second yellow results in a sending-off.'),
  ('fussball-2026-06', 'Which card means a sending-off?', '["Red card","Yellow card","Blue card","Green card"]'::jsonb, 'Red card', 'A red card means a sending-off and the team plays short. The player may not be replaced.'),
  ('fussball-2026-07', 'What do you call three goals by one player in a match?', '["Hat-trick","Brace","Dribble","Offside"]'::jsonb, 'Hat-trick', 'Three goals by one player in a match are called a hat-trick. The goals do not need to be consecutive.'),
  ('fussball-2026-08', 'What happens when the ball fully crosses the touchline?', '["Throw-in","Corner kick","Goal kick","Penalty kick"]'::jsonb, 'Throw-in', 'When the ball fully crosses the touchline, a throw-in is awarded to the opponents. It is taken where the ball went out.'),
  ('fussball-2026-09', 'What is awarded when a defender last touches the ball and it goes over the goal line (no goal)?', '["Corner kick","Goal kick","Kick-off","Dropped ball"]'::jsonb, 'Corner kick', 'If a defender touches the ball last and it goes over the goal line, a corner kick is awarded. It is taken from the nearest corner.'),
  ('fussball-2026-10', 'What is awarded when an attacker last touches the ball and it goes over the goal line (no goal)?', '["Goal kick","Corner kick","Throw-in","Penalty kick"]'::jsonb, 'Goal kick', 'If an attacker touches it last and it goes over the goal line, a goal kick is awarded. It is taken from the goal area.'),
  ('fussball-2026-11', 'When does a goal count?', '["When the ball completely crosses the goal line","When the ball touches the goal line","When the ball hits the post","When the ball touches the goalkeeper"]'::jsonb, 'When the ball completely crosses the goal line', 'A goal counts only when the ball fully crosses the goal line between the posts and under the crossbar. Merely touching the line is not enough.'),
  ('fussball-2026-12', 'Who may handle the ball inside the own penalty area?', '["The goalkeeper","Any defender","The captain","No player"]'::jsonb, 'The goalkeeper', 'Only the goalkeeper may handle the ball inside the own penalty area. Other players commit a handball offense.'),
  ('fussball-2026-13', 'Which equipment is mandatory for outfield players?', '["Shin guards","Headgear","Gloves","Protective goggles"]'::jsonb, 'Shin guards', 'Shin guards are mandatory and must be worn under the socks. They protect against injury.'),
  ('fussball-2026-14', 'What do you call a match with no goals conceded?', '["Clean sheet","Brace","Added time","Offside"]'::jsonb, 'Clean sheet', 'A clean sheet means the team concedes no goals. It is commonly used for goalkeeper and defensive stats.'),
  ('fussball-2026-15', 'From what distance is a penalty kick taken?', '["11 meters","9.15 meters","12 meters","16.5 meters"]'::jsonb, '11 meters', 'A penalty kick is taken from the 11-meter mark. All other players must stay outside the penalty area.'),
  ('fussball-2026-16', 'How far away must opponents be at a free kick?', '["9.15 meters","11 meters","7.32 meters","5 meters"]'::jsonb, '9.15 meters', 'Opponents must be 9.15 m away at a free kick, which equals 10 yards. The wall may move only once the ball is in play.'),
  ('fussball-2026-17', 'What is the minimum number of players to continue a match?', '["7","6","8","9"]'::jsonb, '7', 'A team must have at least 7 players or the match is abandoned. This minimum is fixed in the Laws of the Game.'),
  ('fussball-2026-18', 'When does a goal from an indirect free kick count?', '["After the ball touches another player","Immediately from the kick","Only after a header","Never"]'::jsonb, 'After the ball touches another player', 'On an indirect free kick, the ball must touch another player before a goal can count. A direct goal does not count.'),
  ('fussball-2026-19', 'Which condition is required for a correct throw-in?', '["Both feet on the ground and the ball over the head with both hands","One foot in the air and the ball from the side","Ball with one hand","Roll the ball from the ground"]'::jsonb, 'Both feet on the ground and the ball over the head with both hands', 'For a throw-in, both feet must be on the ground and the ball must be delivered over the head with both hands. The throw is taken from the touchline.'),
  ('fussball-2026-20', 'A player cannot be offside if he is ...', '["in his own half","behind the goalkeeper","dribbling the ball","passing the ball backwards"]'::jsonb, 'in his own half', 'Offside is judged only in the opponents half. In your own half you cannot be offside.'),
  ('fussball-2026-21', 'Which body parts count for offside?', '["All except hands and arms","Only the feet","Only the head","Only the shoulders"]'::jsonb, 'All except hands and arms', 'Offside considers all body parts that can legally score. Hands and arms do not count.'),
  ('fussball-2026-22', 'What is the size of a standard football goal?', '["7.32 m wide and 2.44 m high","6 m wide and 2 m high","8 m wide and 3 m high","7 m wide and 2 m high"]'::jsonb, '7.32 m wide and 2.44 m high', 'A standard goal is 7.32 m wide and 2.44 m high. These dimensions are used internationally.'),
  ('fussball-2026-23', 'What does added time mean?', '["Time added to compensate for stoppages","An extra third period","A break for team meetings","Extra time in knockout matches"]'::jsonb, 'Time added to compensate for stoppages', 'Added time is extra time to compensate for stoppages like injuries or substitutions. It is determined by the referee.'),
  ('fussball-2026-24', 'What is a direct free kick?', '["A free kick from which a goal can be scored directly","A free kick that only counts after a touch","A free kick from the own half","A free kick without a wall"]'::jsonb, 'A free kick from which a goal can be scored directly', 'From a direct free kick, a goal can be scored without another touch. This differs from an indirect free kick.'),
  ('fussball-2026-25', 'What does the referee do when playing advantage?', '["Play continues","Stops play immediately","Shows a yellow card","Awards a corner kick"]'::jsonb, 'Play continues', 'With advantage, the referee allows play to continue if the fouled team benefits. The referee signals with both arms extended.'),
  ('fussball-2026-26', 'What happens if the goalkeeper holds the ball in the hands for more than 6 seconds?', '["Indirect free kick for the opponent","Throw-in for the opponent","Yellow card and penalty kick","Play continues without consequence"]'::jsonb, 'Indirect free kick for the opponent', 'If the goalkeeper holds the ball for more than six seconds, an indirect free kick is awarded to the opponents. This rule prevents time wasting.'),
  ('fussball-2026-27', 'What is a one-two (Doppelpass)?', '["A pass to a teammate and an immediate return pass","Two goals in a match","A long diagonal pass","A pass to the goalkeeper"]'::jsonb, 'A pass to a teammate and an immediate return pass', 'A one-two is a short pass followed by an immediate return pass. It is used to bypass defenders.'),
  ('fussball-2026-28', 'What is a slide tackle?', '["Sliding into the ball to tackle","A spinning shot","A high pass","A corner-kick routine"]'::jsonb, 'Sliding into the ball to tackle', 'A slide tackle is a tackle while sliding. It is fair only if the ball is played first.'),
  ('fussball-2026-29', 'When is a player in an offside position?', '["When he is in the opponents half and closer to the goal line than the ball and the second-last opponent","When he passes the ball backwards","When he is in his own half","When he receives the ball from a throw-in"]'::jsonb, 'When he is in the opponents half and closer to the goal line than the ball and the second-last opponent', 'A player is in an offside position if in the opponents half and nearer to the goal line than the ball and the second-last opponent. It is penalized only when he becomes involved in play.'),
  ('fussball-2026-30', 'A player is level with the second-last opponent. Offside?', '["No, level is not offside","Yes, always offside","Only at a corner kick","Only at a goal kick"]'::jsonb, 'No, level is not offside', 'Being level with the second-last opponent or the ball is not offside. Play should continue in such cases.'),
  ('fussball-2026-31', 'On a penalty kick, the kicker may touch the ball again ...', '["only after another player touches the ball","immediately after the kick","only if the goalkeeper saves","never"]'::jsonb, 'only after another player touches the ball', 'The kicker may touch the ball again only after another player has touched it. This prevents a double touch.'),
  ('fussball-2026-32', 'Where must the opponents be at a kick-off?', '["Outside the center circle and at least 9.15 m from the ball","Inside the center circle","On the halfway line next to the ball","Inside the penalty area"]'::jsonb, 'Outside the center circle and at least 9.15 m from the ball', 'Opponents must be outside the center circle and at least 9.15 m away. The ball is in play once it is kicked and moves.'),
  ('fussball-2026-33', 'What happens if the referee touches the ball and this leads to a promising attack?', '["Dropped ball","Free kick for the attacking team","Throw-in","Penalty kick"]'::jsonb, 'Dropped ball', 'If the referee touches the ball and it creates a promising attack, play restarts with a dropped ball. This restores neutrality.'),
  ('fussball-2026-34', 'What is required of the goalkeeper before a penalty kick is taken?', '["At least one foot on or above the goal line","Both feet behind the line","Both feet in front of the line","He may move freely anywhere"]'::jsonb, 'At least one foot on or above the goal line', 'The goalkeeper must have at least one foot on or above the goal line. He may move laterally but not forward before the kick.'),
  ('fussball-2026-35', 'How does the referee signal an indirect free kick?', '["He raises an arm","He shows a yellow card","He whistles without a signal","He points to the center spot"]'::jsonb, 'He raises an arm', 'The referee raises an arm to signal an indirect free kick. The arm stays up until the ball is touched by another player.'),
  ('fussball-2026-36', 'What applies to the goalkeeper after a deliberate foot pass from a teammate?', '["He may not handle the ball","He may catch the ball","It results in a throw-in","It results in a corner kick"]'::jsonb, 'He may not handle the ball', 'A deliberate foot pass from a teammate may not be handled by the goalkeeper. The same applies to a teammate throw-in.'),
  ('fussball-2026-37', 'Which offense results in an indirect free kick?', '["Playing in a dangerous manner without contact","Kicking an opponent","Pushing an opponent","Handling the ball in the penalty area"]'::jsonb, 'Playing in a dangerous manner without contact', 'Playing in a dangerous manner without contact results in an indirect free kick. An example is a high foot near the head.'),
  ('fussball-2026-38', 'The ball bursts during play. How is play restarted?', '["Dropped ball","Throw-in","Goal kick","Corner kick"]'::jsonb, 'Dropped ball', 'If the ball bursts or becomes defective, the referee stops play and restarts with a dropped ball. The ball is replaced.'),
  ('fussball-2026-39', 'What happens if a player takes a free kick and touches the ball again before anyone else?', '["Indirect free kick for the opponent","Play continues","Yellow card and penalty kick","The free kick is retaken"]'::jsonb, 'Indirect free kick for the opponent', 'If the kicker touches the ball again before anyone else, an indirect free kick is awarded to the opponents. This rule applies to many restarts.'),
  ('fussball-2026-40', 'Can a goal be scored directly from a kick-off?', '["Yes, directly into the opponents goal","No, only after another touch","Only after offside","Only after a pass"]'::jsonb, 'Yes, directly into the opponents goal', 'A goal can be scored directly from a kick-off if the ball goes into the opponents goal. The ball must be kicked and clearly move.')
  ) as t(slug, question, options, correct_answer, explanation)
)
insert into public.question_translations (
  question_id,
  language,
  question,
  options,
  correct_answer,
  explanation
)
select q.id, 'en', t.question, t.options, t.correct_answer, t.explanation
from translations t
join public.questions q on q.slug = t.slug
on conflict (question_id, language) do update
  set question = excluded.question,
      options = excluded.options,
      correct_answer = excluded.correct_answer,
      explanation = excluded.explanation;
